'use client';

import React, { useState } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Play, 
  Info, 
  ChevronLeft,
  Timer,
  Weight,
  Repeat
} from 'lucide-react';
import { cn } from '@/utils/cn';
import { currentWorkout } from '@/utils/treino-data';
import Link from 'next/link';

export default function StudentWorkoutPage() {
  const [workout, setWorkout] = useState(currentWorkout);

  const toggleExercise = (id: string) => {
    setWorkout(prev => ({
      ...prev,
      exercicios: prev.exercicios.map(ex => 
        ex.id === id ? { ...ex, concluido: !ex.concluido } : ex
      )
    }));
  };

  return (
    <div className="space-y-6">
      {/* Header with Back button */}
      <div className="flex items-center gap-4">
        <Link 
          href="/app-aluno"
          className="p-2 -ml-2 bg-white dark:bg-[#0f1117] rounded-xl border border-gray-100 dark:border-[#1e2235] text-gray-500"
        >
          <ChevronLeft className="w-5 h-5" />
        </Link>
        <div>
          <h1 className="text-xl font-bold text-gray-900 dark:text-white">{workout.titulo}</h1>
          <p className="text-xs text-gray-400 font-medium">Treino {workout.tipo} • {workout.exercicios.length} exercícios</p>
        </div>
      </div>

      {/* Exercise List */}
      <div className="space-y-4">
        {workout.exercicios.map((ex, index) => (
          <div 
            key={ex.id}
            className={cn(
              "bg-white dark:bg-[#0f1117] rounded-[24px] border transition-all overflow-hidden",
              ex.concluido 
                ? "border-emerald-100 dark:border-green-900/30 opacity-70" 
                : "border-gray-100 dark:border-[#1e2235] shadow-sm"
            )}
          >
            <div className="p-5">
              {/* Top Row: Number + Title + Video */}
              <div className="flex items-start justify-between gap-3 mb-4">
                <div className="flex items-center gap-3">
                  <div className={cn(
                    "w-7 h-7 rounded-lg flex items-center justify-center text-[10px] font-bold",
                    ex.concluido ? "bg-emerald-500 text-white" : "bg-gray-100 dark:bg-gray-800 text-gray-400"
                  )}>
                    {index + 1}
                  </div>
                  <h4 className={cn("font-bold text-sm", ex.concluido ? "text-gray-400 line-through" : "text-gray-900 dark:text-white")}>
                    {ex.nome}
                  </h4>
                </div>
                {ex.videoUrl && (
                  <button 
                    title="Ver vídeo demonstrativo"
                    aria-label={`Ver vídeo de ${ex.nome}`}
                    className="p-2 bg-primary-50 dark:bg-primary-900/20 rounded-xl text-primary-600"
                  >
                    <Play className="w-4 h-4 fill-current" />
                  </button>
                )}
              </div>

              {/* Stats Row */}
              <div className="grid grid-cols-3 gap-2 mb-4">
                <div className="flex flex-col items-center p-2 bg-gray-50 dark:bg-[#1a1d27] rounded-xl">
                  <Repeat className="w-3 h-3 text-gray-400 mb-1" />
                  <span className="text-[10px] font-bold text-gray-900 dark:text-white">{ex.series} Séries</span>
                </div>
                <div className="flex flex-col items-center p-2 bg-gray-50 dark:bg-[#1a1d27] rounded-xl">
                  <Weight className="w-3 h-3 text-gray-400 mb-1" />
                  <span className="text-[10px] font-bold text-gray-900 dark:text-white">{ex.repeticoes} Reps</span>
                </div>
                <div className="flex flex-col items-center p-2 bg-gray-50 dark:bg-[#1a1d27] rounded-xl">
                  <Timer className="w-3 h-3 text-gray-400 mb-1" />
                  <span className="text-[10px] font-bold text-gray-900 dark:text-white">{ex.descanso}s Desc.</span>
                </div>
              </div>

              {/* Action: Toggle Concluido */}
              <button 
                onClick={() => toggleExercise(ex.id)}
                className={cn(
                  "w-full py-3 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2",
                  ex.concluido 
                    ? "bg-emerald-50 text-emerald-600 border border-emerald-100" 
                    : "bg-gray-900 text-white hover:bg-black"
                )}
              >
                {ex.concluido ? (
                  <>
                    <CheckCircle2 className="w-4 h-4" />
                    Concluído
                  </>
                ) : (
                  <>Finalizar Exercício</>
                )}
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Footer Summary */}
      <div className="fixed bottom-24 left-6 right-6 md:max-w-[384px] md:mx-auto">
        <button className="w-full py-4 bg-primary-600 text-white rounded-2xl font-bold shadow-xl shadow-primary-200 dark:shadow-none flex items-center justify-center gap-2">
          Finalizar Treino
        </button>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { supabase } from '@/lib/supabase';
import { useRouter } from 'next/navigation';
import { Dumbbell, Lock, Mail, User, Loader2, Phone } from 'lucide-react';
import { useToast } from '@/components/ui/toast';
import Link from 'next/link';

export default function CadastroPage() {
  const [nome, setNome] = useState('');
  const [email, setEmail] = useState('');
  const [telefone, setTelefone] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const { showToast } = useToast();

  const handleCadastro = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      // 1. Verificar se o e-mail já está cadastrado no sistema
      const { data: existingProfile, error: searchError } = await supabase
        .from('profiles')
        .select('id')
        .eq('email', email)
        .maybeSingle();

      if (existingProfile) {
        throw new Error('Este e-mail já está cadastrado no sistema. Tente fazer login.');
      }

      // 2. Criar conta (Apenas como 'aluno' para cadastros públicos)
      const { data, error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: {
            nome,
            telefone,
            role: 'aluno'
          }
        }
      });

      if (error) throw error;

      showToast('Conta criada com sucesso! Verifique seu e-mail se necessário.', 'success', 'Bem-vindo!');
      router.push('/login');
    } catch (error: any) {
      showToast(error.message || 'Falha ao criar conta.', 'error', 'Erro no Cadastro');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] dark:bg-[#080a0f] flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        {/* Logo */}
        <div className="flex flex-col items-center mb-8 text-center">
          <div className="w-16 h-16 bg-gradient-to-br from-primary-500 to-primary-700 rounded-2xl flex items-center justify-center shadow-lg shadow-primary-200 dark:shadow-none mb-4 transform hover:rotate-6 transition-transform">
            <Dumbbell className="text-white w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white mt-2">
            Moviment <span className="text-primary-600 dark:text-primary-400">Academy</span>
          </h1>
          <p className="text-sm text-gray-400 mt-1 max-w-[250px]">Entre para o time e comece sua jornada fitness.</p>
        </div>

        {/* Formulário */}
        <div className="bg-white dark:bg-[#12141c] p-8 rounded-3xl shadow-xl shadow-gray-200/50 dark:shadow-none border border-gray-100 dark:border-[#1e2235]">
          <form onSubmit={handleCadastro} className="space-y-5">
            <div>
              <label className="block text-[11px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-2">
                Como devemos te chamar?
              </label>
              <div className="relative">
                <User className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <input
                  type="text"
                  required
                  value={nome}
                  onChange={(e) => setNome(e.target.value)}
                  className="w-full pl-10 pr-4 py-3 bg-gray-50 dark:bg-[#1a1d27] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all"
                  placeholder="Seu nome completo"
                />
              </div>
            </div>

            <div>
              <label className="block text-[11px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-2">
                Seu melhor e-mail
              </label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full pl-10 pr-4 py-3 bg-gray-50 dark:bg-[#1a1d27] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all"
                  placeholder="exemplo@email.com"
                />
              </div>
            </div>

          <div>
            <label className="block text-[11px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-2">
              WhatsApp / Contato
            </label>
            <div className="relative">
              <Phone className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
              <input
                type="tel"
                required
                value={telefone}
                onChange={(e) => setTelefone(e.target.value)}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 dark:bg-[#1a1d27] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all"
                placeholder="(00) 00000-0000"
              />
            </div>
          </div>

            <div>
              <label className="block text-[11px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-2">
                Senha de Acesso
              </label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <input
                  type="password"
                  required
                  minLength={6}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full pl-10 pr-4 py-3 bg-gray-50 dark:bg-[#1a1d27] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all"
                  placeholder="••••••••"
                />
              </div>
              <p className="text-[10px] text-gray-400 mt-2">Mínimo de 6 caracteres.</p>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full py-4 bg-primary-600 text-white rounded-xl text-sm font-bold hover:bg-primary-700 transition-all shadow-lg shadow-primary-200 dark:shadow-none flex items-center justify-center gap-2 disabled:opacity-70"
            >
              {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Começar Agora'}
            </button>

            <div className="pt-4 border-t border-gray-100 dark:border-gray-800 text-center space-y-3">
              <Link href="/login" className="block text-xs font-semibold text-gray-500 hover:text-primary-600 dark:text-gray-400 transition-colors">
                Já tem conta? <span className="text-primary-600 dark:text-primary-400">Entrar no sistema</span>
              </Link>

              <div className="px-4 py-2 bg-amber-50 dark:bg-amber-900/10 rounded-lg">
                <p className="text-[10px] text-amber-700 dark:text-amber-400 font-medium">
                  <strong>Aviso:</strong> Professores, recepcionistas e administradores devem ser cadastrados manualmente pelo Suporte Técnico.
                </p>
              </div>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useRef } from 'react';
import {
  X, Phone, Mail, MapPin, Calendar, CreditCard, Target,
  TrendingUp, Activity, ShieldAlert, Edit3, UserX, MessageCircle
} from 'lucide-react';
import { cn } from '@/utils/cn';
import { StatusBadge, PlanBadge, RiskIndicator } from './status-badge';
import type { Aluno } from '@/types/aluno';
import { openWhatsApp, generateWAMessage } from '@/utils/whatsapp-helper';

interface AlunoDrawerProps {
  aluno: Aluno | null;
  open: boolean;
  onClose: () => void;
  onEdit: (aluno: Aluno) => void;
}

export function AlunoDrawer({ aluno, open, onClose, onEdit }: AlunoDrawerProps) {
  const drawerRef = useRef<HTMLDivElement>(null);

  // Close on Escape key
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (open) {
      document.addEventListener('keydown', handler);
      document.body.style.overflow = 'hidden';
    }
    return () => {
      document.removeEventListener('keydown', handler);
      document.body.style.overflow = '';
    };
  }, [open, onClose]);

  // Focus trap
  useEffect(() => {
    if (open && drawerRef.current) {
      drawerRef.current.focus();
    }
  }, [open]);

  if (!open || !aluno) return null;

  const getInitials = (name: string) => {
    const parts = name.split(' ');
    return (parts[0]?.[0] || '') + (parts[parts.length - 1]?.[0] || '');
  };

  const avatarColors = [
    'from-primary-500 to-indigo-600',
    'from-emerald-500 to-teal-600',
    'from-amber-500 to-orange-600',
    'from-pink-500 to-rose-600',
    'from-violet-500 to-purple-600',
    'from-sky-500 to-blue-600',
  ];

  const infoItems = [
    { icon: Phone, label: 'Telefone', value: aluno.telefone },
    { icon: Mail, label: 'Email', value: aluno.email },
    { icon: MapPin, label: 'Endereço', value: aluno.endereco },
    { icon: Calendar, label: 'Nascimento', value: aluno.dataNascimento },
    { icon: Calendar, label: 'Matrícula', value: aluno.dataMatricula },
    { icon: Target, label: 'Objetivo', value: aluno.objetivo },
