'use client';

import React from 'react';
import { TrendingDown, AlertTriangle, ArrowDownRight, ArrowUpRight, ShieldAlert } from 'lucide-react';
import { cn } from '@/utils/cn';
import type { ChurnDistribution } from '@/types/churn';

/**
 * ChurnCard — Top-level KPI card for churn metrics.
 * 
 * Displays:
 * - Current churn rate (%) with trend indicator
 * - Number of students at risk (alto)
 * - Mini distribution bar (alto/médio/baixo)
 * 
 * Follows the same design system as KPICards (rounded-2xl, shadow-sm, etc.)
 */

interface ChurnCardProps {
  currentRate: number;
  trend: 'up' | 'down';
  change: string;
  atRiskCount: number;
  distribution: ChurnDistribution;
  className?: string;
}

export function ChurnCard({
  currentRate,
  trend,
  change,
  atRiskCount,
  distribution,
  className,
}: ChurnCardProps) {
  // For churn, "down" is positive (good)
  const isPositive = trend === 'down';

  return (
    <div
      className={cn(
        "relative overflow-hidden bg-white dark:bg-[#0f1117] p-6 rounded-2xl border border-gray-100 dark:border-[#1e2235]",
        "shadow-sm hover:shadow-lg dark:hover:shadow-2xl dark:hover:shadow-red-500/5",
        "transition-all duration-300 group cursor-default animate-slide-up",
        className
      )}
      role="region"
      aria-label={`Taxa de Churn: ${currentRate}%`}
    >
      {/* Background gradient decoration */}
      <div
        className="absolute top-0 right-0 w-40 h-40 bg-gradient-to-bl from-red-500/8 to-transparent rounded-full -translate-y-1/2 translate-x-1/2 opacity-60 group-hover:opacity-100 transition-opacity"
        aria-hidden="true"
      />

      {/* Animated pulse ring for high-risk emphasis */}
      <div className="absolute top-4 right-4 w-3 h-3" aria-hidden="true">
        <span className="absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75 animate-ping" />
        <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500" />
      </div>

      <div className="relative z-10">
        {/* Header */}
        <div className="flex justify-between items-start mb-4">
          <div className="p-2.5 rounded-xl bg-danger-50 dark:bg-red-900/20">
            <ShieldAlert className="w-5 h-5 text-danger-600 dark:text-red-400" />
          </div>
          <div
            className={cn(
              "flex items-center gap-1 px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wider",
              isPositive
                ? "bg-success-50 dark:bg-green-900/20 text-success-700 dark:text-green-400"
                : "bg-danger-50 dark:bg-red-900/20 text-danger-700 dark:text-red-400"
            )}
          >
            {isPositive ? (
              <ArrowDownRight className="w-3 h-3" />
            ) : (
              <ArrowUpRight className="w-3 h-3" />
            )}
            {change}
          </div>
        </div>

        {/* Main Metric */}
        <div className="mb-4">
          <p className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-1.5">
            Churn Preditivo (IA)
          </p>
          <h3 className="text-3xl font-bold text-gray-900 dark:text-white leading-none tracking-tight">
            {currentRate}%
          </h3>
        </div>

        {/* At Risk Badge */}
        <div className="flex items-center gap-2 mb-4">
          <AlertTriangle className="w-3.5 h-3.5 text-red-500" />
          <span className="text-xs font-bold text-red-600 dark:text-red-400">
            {atRiskCount} aluno{atRiskCount !== 1 ? 's' : ''} em risco alto
          </span>
        </div>

        {/* Mini Distribution Bar */}
        <div className="space-y-2">
          <div className="flex h-2 rounded-full overflow-hidden bg-gray-100 dark:bg-gray-800">
            <div
              className="bg-red-500 transition-all duration-700"
              style={{ width: `${(distribution.alto / distribution.total) * 100}%` }}
              title={`Alto: ${distribution.alto}`}
            />
            <div
              className="bg-amber-400 transition-all duration-700"
              style={{ width: `${(distribution.medio / distribution.total) * 100}%` }}
              title={`Médio: ${distribution.medio}`}
            />
            <div
              className="bg-emerald-400 transition-all duration-700"
              style={{ width: `${(distribution.baixo / distribution.total) * 100}%` }}
              title={`Baixo: ${distribution.baixo}`}
            />
          </div>
          <div className="flex justify-between text-[10px] font-bold text-gray-400 dark:text-gray-500">
            <span className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-red-500 inline-block" />
              Alto ({distribution.alto})
            </span>
            <span className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-amber-400 inline-block" />
              Médio ({distribution.medio})
            </span>
            <span className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-emerald-400 inline-block" />
              Baixo ({distribution.baixo})
            </span>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { User, Camera, Save, Loader2 } from 'lucide-react';
import { useToast } from '@/components/ui/toast';
import { supabase } from '@/lib/supabase';
import type { UserProfile } from '@/types/auth';

interface ProfileFormProps {
  profile: UserProfile;
}

const roleLabelMap = { 
  admin: 'Administrador', 
  professor: 'Professor / Treinador', 
  recepcao: 'Recepção', 
  aluno: 'Aluno' 
};

export function ProfileForm({ profile }: ProfileFormProps) {
  const { showToast } = useToast();
  const [form, setForm] = useState({ 
    nome: profile.nome || '', 
    email: profile.email || '',
    telefone: (profile as any).telefone || '',
    role: profile.role || 'aluno',
    avatar_url: profile.avatar_url || ''
  });
  const [loading, setLoading] = useState(false);
  const fileInputRef = React.useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setForm(prev => ({ ...prev, avatar_url: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = async () => {
    setLoading(true);
    try {
      // 1. O e-mail fica no auth e o nome na tabela profiles + auth metadata
      const updates = [];

      if (form.email !== profile.email) {
        updates.push(supabase.auth.updateUser({ email: form.email }));
      }

      if (form.nome !== profile.nome || form.role !== profile.role || form.avatar_url !== profile.avatar_url) {
        updates.push(supabase.auth.updateUser({ 
          data: { nome: form.nome, role: form.role, avatar_url: form.avatar_url } 
        }));
        updates.push(supabase.from('profiles').update({ 
          nome: form.nome, 
          role: form.role,
          avatar_url: form.avatar_url 
        }).eq('id', profile.id));
      }

      await Promise.all(updates);

      // Update local profile ref to avoid false "success" without reload
      profile.nome = form.nome;
      profile.role = form.role;
      profile.avatar_url = form.avatar_url;

      if (form.email !== profile.email) {
        showToast('Confirme a alteração no seu novo e-mail.', 'warning', 'Verificação Enviada');
      } else {
        showToast('Perfil atualizado com sucesso!', 'success', 'Salvo');
      }
    } catch (error) {
      showToast('Erro ao atualizar perfil.', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-lg font-bold text-gray-900 dark:text-white">Perfil do Usuário</h2>
        <p className="text-xs text-gray-400 mt-0.5">Gerencie suas informações pessoais</p>
      </div>

      {/* Avatar */}
      <div className="flex items-center gap-6">
        <div className="relative group">
          {form.avatar_url ? (
            <img 
              src={form.avatar_url} 
              alt="Avatar" 
              className="w-20 h-20 rounded-2xl object-cover shadow-lg border-2 border-primary-500/20"
            />
          ) : (
            <div className="w-20 h-20 bg-gradient-to-br from-primary-500 to-indigo-600 rounded-2xl flex items-center justify-center text-white text-2xl font-black shadow-lg">
              {form.nome ? form.nome.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase() : 'US'}
            </div>
          )}
          <input 
            type="file" 
            accept="image/*" 
            title="Escolher foto de perfil"
            aria-label="Selecionar imagem do dispositivo"
            className="hidden" 
            ref={fileInputRef} 
            onChange={handleImageUpload}
          />
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            title="Alterar foto de perfil"
            aria-label="Upload de nova foto de perfil"
            className="absolute -bottom-2 -right-2 w-8 h-8 bg-white dark:bg-[#1a1d27] rounded-full border-2 border-gray-200 dark:border-[#2d3348] flex items-center justify-center text-gray-400 hover:text-primary-600 transition-colors shadow-lg cursor-pointer"
          >
            <Camera className="w-4 h-4" />
          </button>
        </div>
        <div>
          <p className="text-sm font-bold text-gray-900 dark:text-white">{profile.nome}</p>
          <p className="text-xs text-gray-400">{profile.email}</p>
          <span className="inline-block mt-1 px-2 py-0.5 bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 text-[9px] font-bold uppercase tracking-widest rounded-md">
            {roleLabelMap[profile.role as keyof typeof roleLabelMap] || profile.role}
          </span>
        </div>
      </div>

      {/* Fields */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label className="block text-[10px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-1.5">Nome Completo</label>
          <input 
            type="text" 
            value={form.nome} 
            onChange={e => setForm(p => ({ ...p, nome: e.target.value }))}
            title="Seu nome completo"
            className="w-full px-3 py-2.5 bg-gray-50 dark:bg-[#1a1d27] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all" 
          />
        </div>
        <div>
          <label htmlFor="profile-email" className="block text-[10px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-1.5">E-mail de Acesso</label>
          <input 
            id="profile-email"
            type="email" 
            value={form.email} 
            onChange={e => setForm(p => ({ ...p, email: e.target.value }))}
            title="Seu endereço de e-mail"
            placeholder="E-mail"
            className="w-full px-3 py-2.5 bg-gray-50 dark:bg-[#1a1d27] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all" 
          />
        </div>
        <div>
          <label className="block text-[10px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-1.5">Telefone</label>
          <input 
            type="text" 
            value={form.telefone} 
            onChange={e => setForm(p => ({ ...p, telefone: e.target.value }))}
            title="Seu número de telefone"
            className="w-full px-3 py-2.5 bg-gray-50 dark:bg-[#1a1d27] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all" 
          />
        </div>
        <div>
          <label htmlFor="profile-role" className="block text-[10px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-1.5">Cargo / Vínculo</label>
          <select 
            id="profile-role"
            value={form.role} 
            disabled
            title="O cargo só pode ser alterado por um administrador"
            className="w-full pl-3 pr-8 py-2.5 bg-gray-100 dark:bg-[#151821] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-400 cursor-not-allowed appearance-none" 
          >
            <option value="admin">Administrador</option>
            <option value="recepcao">Recepção</option>
            <option value="professor">Professor / Treinador</option>
            <option value="aluno">Aluno / Cliente</option>
          </select>
          <p className="text-[9px] text-gray-400 mt-1.5 italic">* Caso precise alterar seu cargo, contate o administrador.</p>
        </div>
      </div>

      <button 
        onClick={handleSave} 
        disabled={loading}
        className="px-5 py-2.5 bg-primary-600 text-white rounded-xl text-sm font-bold hover:bg-primary-700 transition-all shadow-lg shadow-primary-200 dark:shadow-none flex items-center gap-2 disabled:opacity-70"
      >
        {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />} 
        {loading ? 'Salvando...' : 'Salvar Alterações'}
      </button>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { Lock, Shield, LogOut, Eye, EyeOff, Save, Loader2 } from 'lucide-react';
import { useToast } from '@/components/ui/toast';
import { supabase } from '@/lib/supabase';
import { useRouter } from 'next/navigation';

interface SecuritySettingsProps {
  userEmail?: string;
}

export function SecuritySettings({ userEmail }: SecuritySettingsProps) {
  const { showToast } = useToast();
  const [showPw, setShowPw] = useState(false);
  const [twoFA, setTwoFA] = useState(false);
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  const handleUpdatePassword = async () => {
    if (!password || password.length < 6) {
      showToast('A senha deve ter pelo menos 6 caracteres.', 'error');
      return;
    }
    if (password !== confirmPassword) {
      showToast('As senhas não coincidem.', 'error');
      return;
    }

    setLoading(true);
    try {
      const { error } = await supabase.auth.updateUser({ password });
      if (error) throw error;

      showToast('Senha alterada com sucesso!', 'success', 'Segurança');
      setPassword('');
      setConfirmPassword('');
    } catch (error: any) {
      showToast(error.message || 'Erro ao alterar senha.', 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleSignOutAll = async () => {
    try {
      await supabase.auth.signOut();
      router.push('/login');
    } catch (error) {
      showToast('Erro ao encerrar sessões.', 'error');
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-lg font-bold text-gray-900 dark:text-white">Segurança</h2>
        <p className="text-xs text-gray-400 mt-0.5">Proteja sua conta e controle o acesso</p>
      </div>

      {/* Password Change */}
      <div className="bg-gray-50 dark:bg-[#1a1d27] rounded-2xl p-5 space-y-4">
        <div className="flex items-center gap-3 mb-2">
          <div className="w-9 h-9 bg-primary-50 dark:bg-primary-900/20 rounded-xl flex items-center justify-center">
            <Lock className="w-4 h-4 text-primary-600 dark:text-primary-400" />
          </div>
          <div>
            <p className="text-sm font-bold text-gray-900 dark:text-white">Alterar Senha</p>
            <p className="text-[10px] text-gray-400">Mínimo 8 caracteres com letra e número</p>
          </div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div className="relative">
            <label className="block text-[10px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-1.5">Nova Senha</label>
            <input type={showPw ? 'text' : 'password'} placeholder="••••••••"
              value={password}
              onChange={e => setPassword(e.target.value)}
              className="w-full px-3 py-2.5 bg-white dark:bg-[#0f1117] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all pr-10" />
            <button 
              onClick={() => setShowPw(!showPw)} 
              title={showPw ? "Ocultar senha" : "Ver senha"}
              aria-label={showPw ? "Ocultar senha" : "Ver senha"}
              className="absolute right-3 top-[34px] text-gray-400 hover:text-gray-600"
            >
              {showPw ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            </button>
          </div>
          <div>
            <label className="block text-[10px] uppercase tracking-widest font-bold text-gray-500 dark:text-gray-400 mb-1.5">Confirmar Senha</label>
            <input type="password" placeholder="••••••••"
              value={confirmPassword}
              onChange={e => setConfirmPassword(e.target.value)}
              className="w-full px-3 py-2.5 bg-white dark:bg-[#0f1117] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none transition-all" />
          </div>
        </div>
        <button 
          onClick={handleUpdatePassword} 
          disabled={loading}
          className="px-4 py-2 bg-primary-600 text-white rounded-xl text-xs font-bold hover:bg-primary-700 transition-all flex items-center gap-2 disabled:opacity-70"
        >
          {loading ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Save className="w-3.5 h-3.5" />} 
          {loading ? 'Atualizando...' : 'Atualizar Senha'}
        </button>
      </div>

      {/* 2FA */}
      <div className="bg-gray-50 dark:bg-[#1a1d27] rounded-2xl p-5">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-emerald-50 dark:bg-green-900/20 rounded-xl flex items-center justify-center">
              <Shield className="w-4 h-4 text-emerald-600 dark:text-green-400" />
            </div>
            <div>
              <p className="text-sm font-bold text-gray-900 dark:text-white">Autenticação em 2 Fatores</p>
              <p className="text-[10px] text-gray-400">Adicione uma camada extra de segurança</p>
            </div>
          </div>
          <button 
            onClick={() => { setTwoFA(!twoFA); showToast(twoFA ? '2FA desativado' : '2FA ativado com sucesso!', twoFA ? 'info' : 'success', 'Segurança'); }}
            title={twoFA ? "Desativar 2FA" : "Ativar 2FA"}
            aria-label={twoFA ? "Desativar 2FA" : "Ativar 2FA"}
            className={`relative w-12 h-6 rounded-full transition-all ${twoFA ? 'bg-emerald-500' : 'bg-gray-300 dark:bg-gray-600'}`}>
            <div className={`absolute top-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform ${twoFA ? 'translate-x-6' : 'translate-x-0.5'}`} />
          </button>
        </div>
      </div>

      {/* Logout All */}
      <div className="bg-red-50 dark:bg-red-900/10 rounded-2xl p-5 border border-red-100 dark:border-red-800/30">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-red-100 dark:bg-red-900/20 rounded-xl flex items-center justify-center">
              <LogOut className="w-4 h-4 text-red-600 dark:text-red-400" />
            </div>
            <div>
              <p className="text-sm font-bold text-gray-900 dark:text-white">Encerrar Todas as Sessões</p>
              <p className="text-[10px] text-gray-400">Desconectar de todos os dispositivos</p>
            </div>
          </div>
          <button onClick={handleSignOutAll}
            className="px-4 py-2 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 rounded-xl text-xs font-bold hover:bg-red-100 dark:hover:bg-red-900/20 transition-all">
            Encerrar
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { UserPlus, MoreVertical, ShieldCheck, ShieldAlert, Clock } from 'lucide-react';
import { cn } from '@/utils/cn';
import { useToast } from '@/components/ui/toast';
import type { SystemUser, UserRole } from '@/types/configuracoes';

interface UserManagementProps { users: SystemUser[]; }

const roleConfig: Record<UserRole, { label: string; color: string; bg: string }> = {
  admin: { label: 'Admin', color: 'text-primary-600 dark:text-primary-400', bg: 'bg-primary-50 dark:bg-primary-900/20' },
  ceo: { label: 'CEO', color: 'text-purple-600 dark:text-purple-400', bg: 'bg-purple-50 dark:bg-purple-900/20' },
  professor: { label: 'Professor / Treinador', color: 'text-emerald-600 dark:text-green-400', bg: 'bg-emerald-50 dark:bg-green-900/20' },
  recepcao: { label: 'Recepção', color: 'text-amber-600 dark:text-amber-400', bg: 'bg-amber-50 dark:bg-amber-900/20' },
  aluno: { label: 'Aluno', color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-900/20' },
};

export function UserManagement({ users: initialUsers }: UserManagementProps) {
  const { showToast } = useToast();
  const [users, setUsers] = useState(initialUsers);
  const [showForm, setShowForm] = useState(false);
  const [newUser, setNewUser] = useState({ nome: '', email: '', role: 'professor' as UserRole });

  const addUser = () => {
    if (!newUser.nome || !newUser.email) {
      showToast('Por favor, preencha nome e e-mail.', 'warning');
      return;
    }
    setUsers(prev => [...prev, { ...newUser, id: `u${Date.now()}`, ativo: true, ultimoAcesso: 'Novo' }]);
    setNewUser({ nome: '', email: '', role: 'professor' });
    setShowForm(false);
    showToast(`Usuário "${newUser.nome}" criado com sucesso!`, 'success', 'Novo Profissional');
  };

  const toggleUser = (id: string) => {
    setUsers(prev => prev.map(u => u.id === id ? { ...u, ativo: !u.ativo } : u));
    showToast('Status do usuário atualizado', 'info', 'Usuários');
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-bold text-gray-900 dark:text-white">Permissões e Usuários</h2>
          <p className="text-xs text-gray-400 mt-0.5">{users.filter(u => u.ativo).length} ativos de {users.length} cadastrados</p>
        </div>
        <button onClick={() => setShowForm(!showForm)} className="px-4 py-2 bg-primary-600 text-white rounded-xl text-xs font-bold hover:bg-primary-700 transition-all flex items-center gap-2">
          <UserPlus className="w-3.5 h-3.5" /> Novo Usuário
        </button>
      </div>

      {/* New User Form */}
      {showForm && (
        <div className="bg-primary-50 dark:bg-primary-900/10 border border-primary-100 dark:border-primary-800/30 rounded-2xl p-5 space-y-4 animate-fade-in">
          <h3 className="text-sm font-bold text-gray-900 dark:text-white">Cadastrar Novo Usuário</h3>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            <input type="text" placeholder="Nome" value={newUser.nome} onChange={e => setNewUser(p => ({ ...p, nome: e.target.value }))}
              className="px-3 py-2.5 bg-white dark:bg-[#0f1117] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm focus:ring-2 focus:ring-primary-500 outline-none text-gray-900 dark:text-white" />
            <input type="email" placeholder="E-mail" value={newUser.email} onChange={e => setNewUser(p => ({ ...p, email: e.target.value }))}
              className="px-3 py-2.5 bg-white dark:bg-[#0f1117] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm focus:ring-2 focus:ring-primary-500 outline-none text-gray-900 dark:text-white" />
              <select 
                title="Novo cargo"
                aria-label="Cargo do novo usuário"
                value={newUser.role} 
                onChange={e => setNewUser(p => ({ ...p, role: e.target.value as UserRole }))}
                className="px-3 py-2.5 bg-white dark:bg-[#0f1117] border border-gray-200 dark:border-[#2d3348] rounded-xl text-sm focus:ring-2 focus:ring-primary-500 outline-none text-gray-900 dark:text-white"
              >
              <option value="professor">Professor / Treinador</option>
              <option value="recepcao">Recepção</option>
              <option value="admin">Administrador</option>
              <option value="ceo">CEO</option>
            </select>
          </div>
          <div className="flex gap-2">
            <button onClick={addUser} className="px-4 py-2 bg-primary-600 text-white rounded-xl text-xs font-bold hover:bg-primary-700 transition-all">Criar Usuário</button>
            <button onClick={() => setShowForm(false)} className="px-4 py-2 border border-gray-200 dark:border-[#2d3348] text-gray-600 dark:text-gray-400 rounded-xl text-xs font-bold hover:bg-gray-50 dark:hover:bg-[#1a1d27] transition-all">Cancelar</button>
          </div>
        </div>
      )}

      {/* User Table */}
      <div className="space-y-2">
        {users.map(user => {
          const cfg = roleConfig[user.role];
          return (
            <div key={user.id} className={cn(
              "flex items-center justify-between p-4 bg-gray-50 dark:bg-[#1a1d27] rounded-xl transition-all",
              !user.ativo && "opacity-50"
            )}>
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-gradient-to-br from-gray-200 to-gray-300 dark:from-gray-700 dark:to-gray-600 rounded-xl flex items-center justify-center text-[10px] font-bold text-gray-600 dark:text-gray-300">
                  {user.nome.split(' ').map(n => n[0]).join('').slice(0, 2)}
                </div>
                <div>
                  <p className="text-sm font-bold text-gray-900 dark:text-white">{user.nome}</p>
                  <p className="text-[10px] text-gray-400">{user.email}</p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                <span className={cn("hidden sm:inline-flex px-2 py-0.5 rounded-md text-[9px] font-bold uppercase tracking-widest", cfg.bg, cfg.color)}>
                  {cfg.label}
                </span>
                <span className="hidden md:flex items-center gap-1 text-[10px] text-gray-400">
                  <Clock className="w-3 h-3" /> {user.ultimoAcesso}
                </span>
                <button 
                  onClick={() => toggleUser(user.id)} 
                  title={user.ativo ? "Desativar usuário" : "Ativar usuário"}
                  aria-label={user.ativo ? "Desativar usuário" : "Ativar usuário"}
                  className={cn(
                    "relative w-10 h-5 rounded-full transition-all",
                    user.ativo ? "bg-emerald-500" : "bg-gray-300 dark:bg-gray-600"
                  )}
                >
                  <div className={cn("absolute top-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform", user.ativo ? "translate-x-5" : "translate-x-0.5")} />
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import { Clock, User, Dumbbell, CheckCircle, XCircle, Calendar as CalIcon } from 'lucide-react';
import { cn } from '@/utils/cn';
import { eventTypeConfig, eventStatusConfig } from '@/types/cronograma';
import type { CalendarEvent } from '@/types/cronograma';

interface DaySidebarProps {
  date: string; // YYYY-MM-DD
  events: CalendarEvent[];
  onEventClick: (event: CalendarEvent) => void;
  onCheckIn: (eventId: string) => void;
}

const MONTHS = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
const WEEKDAYS_FULL = ['Domingo','Segunda-feira','Terça-feira','Quarta-feira','Quinta-feira','Sexta-feira','Sábado'];

function parseDate(s: string) {
  const [y, m, d] = s.split('-').map(Number);
  return new Date(y, m - 1, d);
}

export function DaySidebar({ date, events, onEventClick, onCheckIn }: DaySidebarProps) {
  const dt = parseDate(date);
  const dayName = WEEKDAYS_FULL[dt.getDay()];
  const dayNum = dt.getDate();
  const monthName = MONTHS[dt.getMonth()];

  const sorted = [...events].sort((a, b) => a.horaInicio.localeCompare(b.horaInicio));

  return (
    <div className="bg-white dark:bg-[#0f1117] rounded-2xl border border-gray-100 dark:border-[#1e2235] overflow-hidden h-fit lg:sticky lg:top-24">
      {/* Header */}
      <div className="p-5 border-b border-gray-100 dark:border-[#1e2235] bg-gradient-to-br from-primary-600 to-indigo-700 text-white">
        <p className="text-[10px] uppercase tracking-widest font-bold opacity-70">{dayName}</p>
        <p className="text-3xl font-black">{dayNum}</p>
        <p className="text-sm opacity-80">{monthName} {dt.getFullYear()}</p>
        <div className="mt-2 flex items-center gap-2">
          <CalIcon className="w-3.5 h-3.5 opacity-60" />
          <span className="text-xs font-bold opacity-80">{events.length} evento{events.length !== 1 ? 's' : ''}</span>
        </div>
      </div>

      {/* Events List */}
      <div className="p-4 space-y-3 max-h-[500px] overflow-y-auto">
        {sorted.length === 0 ? (
          <div className="text-center py-8">
            <CalIcon className="w-8 h-8 text-gray-200 dark:text-gray-700 mx-auto mb-2" />
            <p className="text-xs text-gray-400 font-medium">Nenhum evento neste dia</p>
          </div>
        ) : sorted.map(ev => {
          const typeCfg = eventTypeConfig[ev.tipo];
          const statusCfg = eventStatusConfig[ev.status];
          return (
            <div
              key={ev.id}
              onClick={() => onEventClick(ev)}
              className={cn(
                "w-full p-3.5 rounded-xl border text-left transition-all hover:shadow-md group cursor-pointer",
                typeCfg.border, typeCfg.bg
              )}
            >
              <div className="flex items-start justify-between mb-2">
                <div className="flex items-center gap-2">
                  <div className={cn("w-2.5 h-2.5 rounded-full", typeCfg.dot)} />
                  <span className={cn("text-[9px] font-bold uppercase tracking-widest", typeCfg.color)}>{typeCfg.label}</span>
                </div>
                <span className={cn("px-1.5 py-0.5 rounded text-[8px] font-bold uppercase", statusCfg.bg, statusCfg.color)}>
                  {statusCfg.label}
                </span>
              </div>
              <p className="text-sm font-bold text-gray-900 dark:text-white mb-1.5 leading-tight">{ev.titulo}</p>
              <div className="flex items-center gap-3 text-[10px] text-gray-500 dark:text-gray-400">
                <span className="flex items-center gap-1"><Clock className="w-3 h-3" />{ev.horaInicio} - {ev.horaFim}</span>
                <span className="flex items-center gap-1"><User className="w-3 h-3" />{ev.instrutorNome}</span>
              </div>

              {/* Quick Check-in */}
              {ev.status === 'agendado' && (
                <div className="mt-3 flex gap-2" onClick={e => e.stopPropagation()}>
                  <button
                    onClick={() => onCheckIn(ev.id)}
                    className="flex-1 py-1.5 bg-emerald-600 text-white rounded-lg text-[10px] font-bold hover:bg-emerald-700 transition-all flex items-center justify-center gap-1"
                  >
                    <CheckCircle className="w-3 h-3" /> Check-in
                  </button>
                  <button 
                    title="Remover evento"
                    aria-label="Remover evento da agenda rápida"
                    className="px-3 py-1.5 border border-gray-200 dark:border-[#2d3348] text-gray-400 rounded-lg text-[10px] font-bold hover:bg-gray-100 dark:hover:bg-gray-800 transition-all font-bold"
                  >
                    <XCircle className="w-3 h-3" />
                  </button>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

