                            )}
                            style={{ width: `var(--risk-w, ${student.score}%)` } as React.CSSProperties}
                            role="progressbar"
                            {...({
                              'aria-valuenow': student.score,
                              'aria-valuemin': 0,
                              'aria-valuemax': 100
                            })}
                            aria-label={`Risco de churn: ${student.score}%`}
                          />
