      {/* Pagination */}
      {processedData.length > 0 && (
        <div className="p-4 border-t border-gray-100 dark:border-[#1e2235] bg-gray-50/30 dark:bg-[#0d0f15] flex flex-col sm:flex-row items-center justify-between gap-3">
