export function CheckinsChart({ data }: CheckinsChartProps) {
  const maxVal = Math.max(...data.map(d => d.quantidade));

  return (
    <div className="bg-white dark:bg-[#0f1117] rounded-2xl border border-gray-100 dark:border-[#1e2235] p-6">
