          </div>
        </div>

        <div className="flex-1 w-full">
          <div className="flex justify-between mb-1.5">
            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
              <Zap className="w-3 h-3 inline mr-1 text-amber-400" />
