  // ⌘K shortcut to focus search
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        searchRef.current?.focus();
      }
      if (e.key === 'Escape' && searchFocused) {
        setSearchQuery('');
        searchRef.current?.blur();
      }
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [searchFocused]);

  // Close notification dropdown on click outside
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setNotifOpen(false);
      }
    };
    if (notifOpen) document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [notifOpen]);

  const markAllRead = () => setNotifications(prev => prev.map(n => ({ ...n, lida: true })));
  const markRead = (id: string) => setNotifications(prev => prev.map(n => n.id === id ? { ...n, lida: true } : n));

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    router.push(`/alunos?search=${encodeURIComponent(searchQuery.trim())}`);
    setSearchQuery('');
  };

  // User display info
  const displayName = user?.nome || 'Usuário';
  const displayRole = roleLabel[user?.role || ''] || user?.role || 'Gestor';
  const initials = displayName.split(' ').map((n: string) => n[0]).join('').slice(0, 2).toUpperCase();

  return (
    <header
      className={cn(
        "sticky top-0 h-16 z-40 transition-all duration-300",
        "bg-white/80 dark:bg-[#0f1117]/80 backdrop-blur-xl",
        "border-b border-gray-100 dark:border-[#1e2235]"
      )}
      role="banner"
    >
      <div className="h-full px-4 md:px-8 flex items-center justify-between gap-4">
        {/* Left: Mobile menu + dynamic page title */}
        <div className="flex items-center gap-3">
          <button
            onClick={onMenuClick}
            className="md:hidden p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl text-gray-500 dark:text-gray-400 transition-colors focus-visible:ring-2 focus-visible:ring-primary-500"
            aria-label="Abrir menu de navegação"
          >
            <Menu className="w-5 h-5" />
          </button>
          <div className="hidden md:block">
            <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Dashboard</h2>
            <p className="text-xs text-gray-400 dark:text-gray-500 -mt-0.5">Visão geral da academia</p>
          </div>
        </div>

        {/* Center: Functional search bar */}
        <div className="flex-1 max-w-md mx-2 md:mx-6">
          <form onSubmit={handleSearch} className="relative group">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 dark:text-gray-500 group-focus-within:text-primary-500 transition-colors" />
            <input
              ref={searchRef}
              type="search"
              id="header-search"
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              onFocus={() => setSearchFocused(true)}
              onBlur={() => setSearchFocused(false)}
              placeholder="Buscar alunos, relatórios... (⌘K)"
              className={cn(
                "w-full pl-10 pr-10 py-2.5 rounded-xl text-sm outline-none transition-all duration-200",
                "bg-gray-50 dark:bg-[#1a1d27] border border-gray-200 dark:border-[#1e2235]",
                "text-gray-900 dark:text-gray-100 placeholder:text-gray-400 dark:placeholder:text-gray-500",
                "focus:ring-2 focus:ring-primary-100 dark:focus:ring-primary-900/30 focus:border-primary-400 dark:focus:border-primary-600 focus:bg-white dark:focus:bg-[#0f1117]"
              )}
              aria-label="Campo de busca global"
            />
            {searchQuery ? (
              <button
                type="button"
                onClick={() => setSearchQuery('')}
                aria-label="Limpar campo de busca"
                title="Limpar busca"
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                <X className="w-4 h-4" />
              </button>
            ) : (
              <kbd className="hidden lg:inline-flex absolute right-3 top-1/2 -translate-y-1/2 items-center gap-0.5 px-1.5 py-0.5 text-[10px] font-mono text-gray-400 bg-gray-100 dark:bg-gray-800 dark:text-gray-500 border border-gray-200 dark:border-gray-700 rounded">
                ⌘K
              </kbd>
            )}
          </form>
        </div>

        {/* Right: Actions */}
        <div className="flex items-center gap-1.5 md:gap-2">
          {/* AI Insight button */}
          <button
            onClick={() => showToast('Analisando padrões de treino e churn...', 'info', 'IA Insights')}
            className="hidden sm:flex items-center gap-2 px-3 py-2 bg-gradient-to-r from-primary-500 to-indigo-600 text-white rounded-xl text-xs font-bold hover:shadow-lg hover:shadow-primary-200 dark:hover:shadow-none transition-all"
            aria-label="Insights da inteligência artificial"
          >
            <Sparkles className="w-3.5 h-3.5" />
            IA Insights
          </button>

          <ThemeToggle />

          {/* Notifications Bell + Dropdown */}
          <div className="relative" ref={dropdownRef}>
            <button
              onClick={() => setNotifOpen(!notifOpen)}
              className="relative p-2.5 text-gray-400 dark:text-gray-500 hover:text-gray-900 dark:hover:text-gray-100 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-xl transition-all focus-visible:ring-2 focus-visible:ring-primary-500"
              aria-label={`Notificações — ${unreadCount} novas`}
            >
              <Bell className="w-[18px] h-[18px]" />
              {unreadCount > 0 && (
                <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-danger-500 text-white text-[9px] font-bold rounded-full flex items-center justify-center border-2 border-white dark:border-[#0f1117] animate-scale-in" aria-hidden="true">
                  {unreadCount}
                </span>
              )}
            </button>

            {/* Dropdown */}
            {notifOpen && (
              <div className="absolute right-0 top-full mt-2 w-80 sm:w-96 bg-white dark:bg-[#0f1117] border border-gray-100 dark:border-[#1e2235] rounded-2xl shadow-2xl overflow-hidden z-50 animate-scale-in">
                {/* Dropdown Header */}
                <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100 dark:border-[#1e2235]">
                  <div>
                    <h3 className="text-sm font-bold text-gray-900 dark:text-white">Notificações</h3>
                    <p className="text-[10px] text-gray-400">{unreadCount} não lida{unreadCount !== 1 ? 's' : ''}</p>
                  </div>
                  {unreadCount > 0 && (
                    <button
                      onClick={markAllRead}
                      className="text-[10px] font-bold text-primary-600 dark:text-primary-400 hover:underline uppercase tracking-widest"
                    >
                      Marcar todas
                    </button>
                  )}
                </div>

                {/* Notification Items */}
                <div className="max-h-72 overflow-y-auto">
                  {notifications.map(notif => {
                    const Icon = notifIconMap[notif.tipo];
                    const colors = notifColorMap[notif.tipo];
                    return (
                      <button
                        key={notif.id}
                        onClick={() => markRead(notif.id)}
                        className={cn(
                          "w-full flex items-start gap-3 px-4 py-3 text-left transition-all hover:bg-gray-50 dark:hover:bg-[#1a1d27]",
                          !notif.lida && "bg-primary-50/50 dark:bg-primary-900/5"
                        )}
                      >
                        <div className={cn("w-8 h-8 rounded-lg flex items-center justify-center shrink-0 mt-0.5", colors)}>
                          <Icon className="w-4 h-4" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            <p className={cn("text-xs font-semibold truncate", notif.lida ? "text-gray-500 dark:text-gray-400" : "text-gray-900 dark:text-white")}>
                              {notif.titulo}
                            </p>
                            {!notif.lida && <div className="w-1.5 h-1.5 bg-primary-500 rounded-full shrink-0" />}
                          </div>
                          <p className="text-[10px] text-gray-400 truncate mt-0.5">{notif.descricao}</p>
                          <p className="text-[9px] text-gray-300 dark:text-gray-600 mt-0.5">{notif.tempo}</p>
                        </div>
                      </button>
                    );
                  })}
                </div>

                {/* Dropdown Footer — now navigates */}
                <div className="px-4 py-2.5 border-t border-gray-100 dark:border-[#1e2235] text-center">
                  <Link
                    href="/relatorios"
                    onClick={() => setNotifOpen(false)}
                    className="text-[10px] font-bold text-primary-600 dark:text-primary-400 uppercase tracking-widest hover:underline"
                  >
                    Ver histórico de atividades →
                  </Link>
                </div>
              </div>
            )}
          </div>

          {/* Divider */}
          <div className="h-8 w-px bg-gray-100 dark:bg-[#1e2235] mx-1 hidden sm:block" aria-hidden="true" />

          {/* User avatar — clickable, goes to /configuracoes */}
          <Link
            href="/configuracoes"
            className="flex items-center gap-3 pl-2 pr-1 py-1 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-2xl transition-all focus-visible:ring-2 focus-visible:ring-primary-500"
            aria-label="Ir para configurações de perfil"
          >
            <div className="text-right hidden sm:block">
              <p className="text-sm font-semibold text-gray-900 dark:text-white leading-tight">{displayName.split(' ')[0]}</p>
              <p className="text-[10px] text-gray-400 dark:text-gray-500 uppercase tracking-widest font-bold">{displayRole}</p>
            </div>
            <div className="w-9 h-9 rounded-xl flex items-center justify-center shadow-lg shadow-primary-200 dark:shadow-none ring-2 ring-white dark:ring-[#0f1117] overflow-hidden">
              {user?.avatar_url ? (
                <img src={user.avatar_url} alt="Avatar" className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full bg-gradient-to-tr from-primary-500 to-indigo-600 flex items-center justify-center">
                  <span className="text-white font-bold text-xs">{initials}</span>
                </div>
              )}
            </div>
          </Link>
        </div>
      </div>
    </header>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import {
  BarChart3,
  Users,
  Settings,
  Calendar,
  CreditCard,
  Dumbbell,
  ChevronLeft,
  LayoutDashboard,
  LogOut,
  X,
  Shield,
} from 'lucide-react';
import { cn } from '@/utils/cn';
import { useMediaQuery } from '@/hooks/use-media-query';
import { useAuth } from '@/hooks/use-auth';

/**
 * Navigation menu items.
 * Active state is derived from the current pathname via Next.js router.
 */
const menuItems = [
  { icon: LayoutDashboard, label: 'Dashboard', href: '/' },
  { icon: Users, label: 'Alunos', href: '/alunos' },
  { icon: BarChart3, label: 'Relatórios', href: '/relatorios' },
  { icon: Calendar, label: 'Cronograma', href: '/cronograma' },
  { icon: CreditCard, label: 'Financeiro', href: '/financeiro' },
  { icon: Dumbbell, label: 'Treinos', href: '/treinos' },
  { icon: Shield, label: 'Biometria', href: '/biometria' },
  { icon: Settings, label: 'Configurações', href: '/configuracoes' },
];

interface SidebarProps {
  mobileOpen?: boolean;
  onMobileClose?: () => void;
}

export function Sidebar({ mobileOpen, onMobileClose }: SidebarProps) {
  const [isCollapsed, setIsCollapsed] = useState(false);
  const isDesktop = useMediaQuery('(min-width: 768px)');
  const pathname = usePathname();
  const { user, signOut } = useAuth();

  // Close mobile sidebar on desktop resize
  useEffect(() => {
    if (isDesktop && onMobileClose) {
      onMobileClose();
    }
  }, [isDesktop, onMobileClose]);

  const sidebarContent = (
    <aside
      className={cn(
        "h-screen bg-white dark:bg-[#0f1117] border-r border-gray-100 dark:border-[#1e2235] transition-all duration-300 flex flex-col",
        // Desktop: fixed sidebar with collapse
        "md:fixed md:left-0 md:top-0 md:z-50",
        isCollapsed ? "md:w-20" : "md:w-64",
        // Mobile: full-width inside drawer
        "w-72"
      )}
      role="navigation"
      aria-label="Menu principal"
    >
      {/* Logo / Brand */}
      <div className="p-5 flex items-center justify-between border-b border-gray-50 dark:border-[#1e2235]">
        <Link
          href="/"
          className={cn(
            "flex items-center gap-3 overflow-hidden transition-all duration-300",
            isCollapsed && "md:opacity-0 md:w-0"
          )}
        >
          <div className="w-9 h-9 bg-gradient-to-br from-primary-500 to-primary-700 rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-primary-200 dark:shadow-none">
            <Dumbbell className="text-white w-5 h-5" />
          </div>
          <div className="whitespace-nowrap">
            <span className="font-bold text-base tracking-tight text-gray-900 dark:text-white">
              Moviment
            </span>
            <span className="text-primary-600 dark:text-primary-400 font-bold">Academy</span>
          </div>
        </Link>

        {/* Desktop: Collapse toggle */}
        <button
          onClick={() => setIsCollapsed(!isCollapsed)}
          className="hidden md:flex p-1.5 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
          aria-label={isCollapsed ? 'Expandir menu' : 'Recolher menu'}
        >
          <ChevronLeft className={cn("w-5 h-5 transition-transform duration-300", isCollapsed && "rotate-180")} />
        </button>

        {/* Mobile: Close button */}
        <button
          onClick={onMobileClose}
          className="md:hidden p-1.5 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg text-gray-400"
          aria-label="Fechar menu"
        >
          <X className="w-5 h-5" />
        </button>
      </div>

      {/* Navigation Links */}
      <nav className="flex-1 px-3 mt-4 space-y-1 overflow-y-auto" aria-label="Navegação do dashboard">
        {menuItems.filter(item => {
          if (!user) return false;
          if (user.role === 'admin' || user.role === 'ceo') return true;
          if (user.role === 'recepcao') {
            return ['Dashboard', 'Alunos', 'Financeiro', 'Biometria'].includes(item.label);
          }
          if (user.role === 'professor') {
            return ['Dashboard', 'Alunos', 'Cronograma', 'Treinos'].includes(item.label);
          }
          return false;
        }).map((item) => {
          const isActive = item.href === '/'
            ? pathname === '/'
            : pathname.startsWith(item.href);

          return (
            <Link
              key={item.label}
              href={item.href}
              onClick={() => {
                // Close mobile sidebar on navigation
                if (!isDesktop && onMobileClose) onMobileClose();
              }}
              className={cn(
                "w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative",
                isActive
                  ? "bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-400"
                  : "text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800/50 hover:text-gray-900 dark:hover:text-gray-100"
              )}
              aria-current={isActive ? 'page' : undefined}
              title={isCollapsed ? item.label : undefined}
            >
              <item.icon className={cn(
                "w-5 h-5 shrink-0 transition-colors",
                isActive
                  ? "text-primary-600 dark:text-primary-400"
                  : "text-gray-400 dark:text-gray-500 group-hover:text-gray-600 dark:group-hover:text-gray-300"
              )} />

              <span className={cn(
                "text-sm font-medium whitespace-nowrap transition-all duration-300",
                isCollapsed && "md:hidden"
              )}>
                {item.label}
              </span>

              {/* Active indicator */}
              {isActive && (
                <div className="absolute left-0 w-1 h-6 bg-primary-600 dark:bg-primary-400 rounded-r-full" />
              )}

              {/* Collapsed tooltip (desktop only) */}
              {isCollapsed && (
                <div className="hidden md:block absolute left-full ml-3 px-3 py-1.5 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 text-xs font-medium rounded-lg opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity whitespace-nowrap z-50 shadow-xl">
                  {item.label}
                </div>
              )}
            </Link>
          );
        })}
      </nav>

      {/* User Profile & Logout */}
      <div className="p-3 border-t border-gray-100 dark:border-[#1e2235] space-y-1">
        {/* Mini user card */}
        {!isCollapsed && user && (
          <div className="flex items-center gap-3 p-3 mb-2 bg-gray-50 dark:bg-gray-800/50 rounded-xl">
            {user.avatar_url ? (
              <img 
                src={user.avatar_url} 
                alt="Avatar" 
                className="w-9 h-9 rounded-xl object-cover shadow-lg shadow-primary-200 dark:shadow-none"
              />
            ) : (
              <div className="w-9 h-9 bg-gradient-to-br from-primary-500 to-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xs shadow-lg shadow-primary-200 dark:shadow-none">
                {user.nome.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase()}
              </div>
            )}
            <div className="flex-1 min-w-0">
              <p className="text-sm font-semibold text-gray-900 dark:text-white truncate">{user.nome}</p>
              <p className="text-[10px] text-gray-400 dark:text-gray-500 uppercase tracking-widest font-bold">{user.role}</p>
            </div>
          </div>
        )}

        <button 
          onClick={async () => {
            if (confirm('Deseja realmente sair do sistema?')) {
              await signOut();
              window.location.href = '/login';
            }
          }}
          className={cn(
            "w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-gray-500 dark:text-gray-400 hover:bg-red-50 dark:hover:bg-red-900/10 hover:text-danger-600 dark:hover:text-red-400 transition-all group",
            isCollapsed && "md:justify-center"
          )}
        >
          <LogOut className="w-5 h-5" />
          <span className={cn(
            "text-sm font-medium",
            isCollapsed && "md:hidden"
          )}>Sair</span>
        </button>
      </div>
    </aside>
  );

  return (
    <>
      {/* Desktop Sidebar */}
      <div className="hidden md:block">
        {sidebarContent}
      </div>

      {/* Mobile Drawer Overlay */}
      {mobileOpen && (
        <div className="fixed inset-0 z-50 md:hidden">
          {/* Overlay backdrop */}
          <div
            className="absolute inset-0 bg-black/50 backdrop-blur-sm"
            onClick={onMobileClose}
            aria-hidden="true"
          />
          {/* Drawer panel */}
          <div className="relative z-10 h-full w-fit animate-slide-in-right">
            {sidebarContent}
          </div>
        </div>
      )}
    </>
  );
}

'use client';

import React, { useState } from 'react';
import { Sidebar } from '@/components/layout/sidebar';
import { Header } from '@/components/layout/header';
import { ProfileForm } from '@/components/dashboard/configuracoes/profile-form';
import { GymForm } from '@/components/dashboard/configuracoes/gym-form';
import { SecuritySettings } from '@/components/dashboard/configuracoes/security-settings';
import { UserManagement } from '@/components/dashboard/configuracoes/user-management';
import { Integrations } from '@/components/dashboard/configuracoes/integrations';
import { PreferencesSettings } from '@/components/dashboard/configuracoes/preferences-settings';
import { currentProfile, gymSettingsData, systemUsersData, integrationsData } from '@/utils/configuracoes-data';
import { User, Building2, Shield, Users, Plug, Settings2, Loader2 } from 'lucide-react';
import { cn } from '@/utils/cn';
import type { SettingsTab } from '@/types/configuracoes';
import { useAuth } from '@/hooks/use-auth';

const tabs: { id: SettingsTab; label: string; icon: React.ElementType; description: string }[] = [
  { id: 'perfil', label: 'Perfil', icon: User, description: 'Dados pessoais' },
  { id: 'academia', label: 'Academia', icon: Building2, description: 'Dados do estabelecimento' },
  { id: 'seguranca', label: 'Segurança', icon: Shield, description: 'Senhas e autenticação' },
  { id: 'usuarios', label: 'Usuários', icon: Users, description: 'Equipe e permissões' },
  { id: 'integracoes', label: 'Integrações', icon: Plug, description: 'APIs e webhooks' },
  { id: 'preferencias', label: 'Preferências', icon: Settings2, description: 'Tema e notificações' },
];

export default function ConfiguracoesPage() {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<SettingsTab>('perfil');
  const { user } = useAuth();

  const renderContent = () => {
    if (!user) return <div className="p-8 flex justify-center"><Loader2 className="w-8 h-8 animate-spin text-primary-500" /></div>;

    switch (activeTab) {
      case 'perfil': return <ProfileForm profile={user as any} />;
      case 'academia': return <GymForm settings={gymSettingsData} />;
      case 'seguranca': return <SecuritySettings userEmail={user.email} />;
      case 'usuarios': return <UserManagement users={systemUsersData} />;
      case 'integracoes': return <Integrations integrations={integrationsData} />;
      case 'preferencias': return <PreferencesSettings />;
    }
  };

  return (
    <div className="flex min-h-screen bg-[#f8fafc] dark:bg-[#080a0f]">
      <Sidebar mobileOpen={mobileMenuOpen} onMobileClose={() => setMobileMenuOpen(false)} />

      <div className="flex-1 md:ml-64 transition-all duration-300">
        <Header onMenuClick={() => setMobileMenuOpen(true)} />

        <main className="px-4 md:px-8 py-8 max-w-7xl mx-auto">
          {!user ? (
            <div className="flex items-center justify-center h-[50vh]">
              <Loader2 className="w-8 h-8 animate-spin text-primary-500" />
            </div>
          ) : (user.role !== 'admin' && user.role !== 'ceo') ? (
            <div className="flex items-center justify-center h-[50vh]">
              <div className="text-center bg-white dark:bg-[#0f1117] p-8 rounded-3xl border border-red-100 dark:border-red-900/30 shadow-lg">
                <Shield className="w-12 h-12 text-red-500 mx-auto mb-4" />
                <h2 className="text-xl font-bold text-gray-900 dark:text-white">Acesso Restrito</h2>
                <p className="text-gray-500 text-sm mt-2">Apenas Administradores e CEOs têm acesso a esta página.</p>
              </div>
            </div>
          ) : (
            <>
              {/* Page Header */}
              <div className="mb-8 animate-fade-in">
                <div className="flex items-center gap-2 mb-1">
                  <span className="px-2 py-0.5 bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400 text-[10px] font-bold uppercase tracking-widest rounded-md">
                    Sistema
                  </span>
                </div>
                <h1 className="text-2xl md:text-3xl font-bold text-gray-900 dark:text-white tracking-tight">
                  Configurações
                </h1>
                <p className="text-gray-500 dark:text-gray-400 mt-1 text-sm">
                  Gerencie seu perfil, academia, segurança e integrações
                </p>
              </div>

              <div className="flex flex-col lg:flex-row gap-6">
                {/* Settings Internal Sidebar */}
                <div className="lg:w-64 shrink-0">
                  {/* Mobile: horizontal scroll tabs */}
                  <div className="flex lg:hidden gap-2 overflow-x-auto pb-2 scroll-hide">
                    {tabs.map(tab => (
                      <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={cn(
                          "flex items-center gap-2 px-4 py-2.5 rounded-xl text-xs font-bold whitespace-nowrap transition-all",
                          activeTab === tab.id
